SELECT DISTINCT year, grande_regiao, uf, produto, codigo_ibge, municipio, vendas FROM (SELECT TRY_CAST(trim("ano") AS INTEGER) AS year, NULLIF(TRIM("grande_regiao"), '') AS grande_regiao, NULLIF(TRIM("uf"), '') AS uf, NULLIF(TRIM("produto"), '') AS produto, NULLIF(TRIM("codigo_ibge"), '') AS codigo_ibge, NULLIF(TRIM("municipio"), '') AS municipio, TRY_CAST(replace(replace(trim("vendas"), '.', ''), ',', '.') AS DOUBLE) AS vendas FROM "anp-brazil-vdpb-vaehdpm-oleo-combustivel-vendas-anuais-de-oleo-combustivel-por-municipio") WHERE year IS NOT NULL AND (vendas IS NOT NULL)
